<?php
/**
 * Production autoloader for Unuspay WooCommerce plugin.
 *
 * Generated by build.sh — replaces the Composer autoloader for distribution.
 * Maps PSR-4 namespaces to their source directories.
 *
 * @package UnusPay\WooCommerce
 */

declare(strict_types=1);

if (!defined('ABSPATH')) {
    exit;
}

spl_autoload_register(static function (string $class): void {
    static $prefixes = [
        'UnusPay\\WooCommerce\\' => __DIR__ . '/../includes/',
        'UnusPay\\SDK\\' => __DIR__ . '/unuspay/unuspay-sdk/src/',
    ];

    foreach ($prefixes as $prefix => $baseDir) {
        $len = strlen($prefix);

        if (strncmp($prefix, $class, $len) !== 0) {
            continue;
        }

        $relativeClass = substr($class, $len);
        $file = $baseDir . str_replace('\\', '/', $relativeClass) . '.php';

        if (file_exists($file)) {
            require $file;
            return;
        }
    }
});
